INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-02249', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡的敘述，下列何者錯誤？', '["軟式隱形眼鏡對角膜散光的矯正效果較差", "硬式隱形眼鏡對不規則散光的矯正效果較好", "低度或沒有散光的患者，卻有明顯的角膜散光，只是其度數恰與晶體散光互相抵消，此類患者應使用 硬式隱形眼鏡矯正", "硬式隱形眼鏡可能因鏡片偏位，而產生具稜鏡度數的淚液鏡片"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02250', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關角膜地形圖（topography）的測量，下列敘述何者錯誤？', '["閱讀書籍時，眼睛往下看，若閱讀一段時間之後馬上做檢查，會影響結果", "上下眼皮會遮住角膜，可輕輕將眼皮撐大，但不要壓迫角膜", "配戴硬式透氣隱形眼鏡，會改變角膜表面的弧度，若要做屈光手術，建議參考停戴 2 周後可進行角膜 地形圖檢查", "角膜地形圖的差異圖，可比較隱形眼鏡戴用一段時間之後角膜的變化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02251', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '一位 39 歲的年輕女性，沒有戴過隱形眼鏡，角膜弧度右眼 44.00D@180/44.25D@090，左眼', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02252', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '50D@180/44.00D@090；自動驗光儀檢查右眼為-3.25DS/-1.25DC×180，左眼為-3.00DS/-1.25DS×180。 則下列何種隱形眼鏡最適合，且可能滿意度較高？', '["軟式散光", "硬式球面", "軟式球面", "硬式散光"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02253', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡造成眼表面變化，下列何者不易以細隙燈顯微鏡觀察到？', '["上下眼瞼的結膜濾泡（follicle）與乳突（papillae）", "配戴角膜塑型片後角膜上皮細胞的厚度改變", "因為缺氧造成的角膜上皮微囊腫（epithelial microcyst）", "長期配戴隱形眼鏡之後的淚膜破裂時間減少"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02254', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關角膜解剖生理的敘述，下列何者正確？', '["角膜神經纖維密度是皮膚約10到50倍以上", "角膜的養分供給來源淚液占最大角色", "支配角膜神經纖維受損後，角膜上皮細胞層受傷癒合不會受影響", "末期角膜內皮細胞失養症時，角膜透明度不受影響"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02255', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '因配戴隱形眼鏡引起的角膜邊缘3點和9點的染色（3 & 9 o''clock staining）之敘述，下列何者錯誤？', '["鏡片邊緣翹角太低、鏡片直徑太大、病人眨眼不完全會引起此併發症", "停止配戴隱形眼鏡後，痊癒後原來染色處一般會留下瘢痕", "若發生於角膜散光大於3.00屈光度時，可配戴後弧散光設計的隱形眼鏡（back toric RGP lens）來避免", "角膜有3點和9點的染色情形，則會引起病人對隱形眼鏡的耐受度降低，甚至會導致減少配戴時間且 眼睛乾澀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02256', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡配戴造成角膜潰瘍的敘述，下列何者錯誤？', '["角膜感染造成之角膜潰瘍，眼睛通常會覺得疼痛或合併怕光流淚等症狀", "在臺灣較常見的致病因子包括細菌、黴菌、病毒，此外棘狀阿米巴原蟲感染則與配戴隱形眼鏡有關連", "自體的免疫力，完整的角膜表皮和充足的淚液是避免角膜感染的關鍵", "外傷、隱形眼鏡配戴為角膜潰瘍常見誘因，其中動植物所造成外傷易導致綠膿桿菌角膜潰瘍，軟式隱 形眼鏡配戴過夜易導致黴菌性感染"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02257', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於乾眼症相關檢查的敘述，下列何者錯誤？', '["乾眼症的檢查一般包含細隙燈檢查、淚半月帶（tear meniscus）高度測量、淚膜破裂時間（tear film break up time）測定、螢光染色、淚液分泌 Schirmer 檢查", "螢光染色可幫助發現角膜上皮破損的位置", "淚半月帶是指在下眼瞼緣與下眼球結膜接觸處的淚液蓄積", "淚液分泌 Schirmer檢查是在點完局部麻醉劑後測量反射淚水的分泌量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02258', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '一位14歲的國中生因為一眼的散光驗光度數在半年內增加300度，沒有眼部創傷或手術病史，也不曾配 戴隱形眼鏡。今要求驗配隱形眼鏡，下列那一種檢查最為重要？', '["睫狀肌麻痺散瞳驗光檢查", "角膜螢光染色細隙燈檢查", "角膜地形圖儀器檢查", "眼壓及眼底視神經檢查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
